// Use the current item's JSON directly
const row = $json;

// ---------- Parse items_with_price (JSON array from SQL) ----------

let raw = [];
if (Array.isArray(row.items_with_price)) {
  raw = row.items_with_price;
} else if (typeof row.items_with_price === 'string') {
  try {
    raw = JSON.parse(row.items_with_price);
  } catch (e) {
    raw = [];
  }
} else if (row.items_with_price && typeof row.items_with_price === 'object') {
  raw = Object.values(row.items_with_price);
}

// Normalize into a clean list of entries
let entries = (raw || [])
  .map(it => {
    if (it && typeof it === 'object') {
      const name = String(
        it.item_name ||
        it.asset_name ||
        it.commodity_name ||
        it.name ||
        ''
      ).trim();

      const assetType = String(it.asset_type || 'unknown').trim() || 'unknown';
      const code = String(it.commodity_code || it.code || '').trim() || null;
      const category = String(it.category || '').trim() || null;
      const priceVal = it.price ?? it.sell_price ?? it.buy_price ?? null;
      const price = priceVal !== null ? Number(priceVal) : null;

      return { name, assetType, code, category, price };
    }

    const name = String(it || '').trim();
    return { name, assetType: 'unknown', code: null, category: null, price: null };
  })
  .filter(it => it.name.length > 0);

// Sort by name for detailed view
entries.sort((a, b) =>
  a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }),
);

const total = Number(row.item_count ?? entries.length) || 0;

// ---------- Price formatting helper ----------

function formatPrice(p) {
  if (p === null || isNaN(p)) return null;
  return p.toLocaleString('en-US', {
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  });
}

// ---------- Shared header ----------

const headerLines = [];

headerLines.push(`# Trade Terminal: ${row.name}`);
headerLines.push('');

if (row.terminal_type) {
  headerLines.push(`- **Type:** ${row.terminal_type}`);
}
if (row.location_name) {
  headerLines.push(`- **Location:** ${row.location_name}`);
}
if (row.system_name) {
  headerLines.push(`- **System:** ${row.system_name}`);
}
headerLines.push(`- **Priced items (all asset types):** ${total}`);
headerLines.push('');

// ---------- Summary selection (2 low, 2 high, 1 middle) ----------

let summaryEntries = [];
let suffixSummary = '';

if (total <= 5) {
  summaryEntries = [...entries];
} else {
  const priced = entries.filter(
    it => it.price !== null && !isNaN(it.price),
  );

  if (priced.length >= 5) {
    const byPriceAsc = [...priced].sort((a, b) => a.price - b.price);
    const n = byPriceAsc.length;

    const idxs = [
      0,                 // lowest
      1,                 // second lowest
      Math.floor(n / 2), // middle
      n - 2,             // second highest
      n - 1,             // highest
    ];

    const chosenMap = new Map();
    for (const idx of idxs) {
      const it = byPriceAsc[idx];
      if (!it) continue;
      const key = it.name + '|' + it.assetType;
      if (!chosenMap.has(key)) chosenMap.set(key, it);
    }

    // Fill up to 5 if we somehow got fewer uniques
    if (chosenMap.size < 5) {
      for (const it of entries) {
        if (chosenMap.size >= 5) break;
        const key = it.name + '|' + it.assetType;
        if (!chosenMap.has(key)) chosenMap.set(key, it);
      }
    }

    summaryEntries = Array.from(chosenMap.values());
  } else {
    // Not enough priced entries, just first 5 alphabetically
    summaryEntries = entries.slice(0, 5);
  }

  suffixSummary = ` (${summaryEntries.length} of ${total})`;
}

// Sort chosen summary set alphabetically for display
summaryEntries.sort((a, b) =>
  a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }),
);

// ---------- SUMMARY MARKDOWN ----------

const summaryLines = [...headerLines];

summaryLines.push(`## Priced Items${suffixSummary}`);
summaryLines.push('');
summaryLines.push('> _Note: Lists below are unordered and not ranked._');
summaryLines.push('');

if (summaryEntries.length === 0) {
  summaryLines.push(
    '_No priced items are currently recorded at this terminal._',
  );
} else {
  for (const it of summaryEntries) {
    const priceText = formatPrice(it.price);
    const codePart = it.code ? ` (${it.code})` : '';
    const typeTag = it.assetType ? ` [${it.assetType}]` : '';
    if (priceText) {
      summaryLines.push(`- ${it.name}${codePart}${typeTag}: ${priceText} aUEC`);
    } else {
      summaryLines.push(`- ${it.name}${codePart}${typeTag}`);
    }
  }
  if (total > summaryEntries.length) {
    summaryLines.push('… and more');
  }
}

// ---------- DETAILED MARKDOWN ----------

const detailedLines = [...headerLines];

detailedLines.push('## Priced Items');
detailedLines.push('');
detailedLines.push(
  '> _Detailed view. Lists below are unordered and not ranked._',
);
detailedLines.push('');

if (entries.length === 0) {
  detailedLines.push(
    '_No priced items are currently recorded at this terminal._',
  );
} else {
  for (const it of entries) {
    const priceText = formatPrice(it.price);
    const codePart = it.code ? ` (${it.code})` : '';
    const typeTag = it.assetType ? ` [${it.assetType}]` : '';
    if (priceText) {
      detailedLines.push(`- ${it.name}${codePart}${typeTag}: ${priceText} aUEC`);
    } else {
      detailedLines.push(`- ${it.name}${codePart}${typeTag}`);
    }
  }
}

// ---------- Slug + file paths ----------

const slug = String(row.name || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const filePathSummary = `/RAG/KB/terminals/${slug}.md`;
const filePathDetailed = `/RAG/KB/terminals/${slug}_detailed.md`;

return [
  {
    json: {
      terminal_id: row.id,
      slug,
      name: row.name,

      item_count: total,

      markdown_summary: summaryLines.join('\n'),
      filePath_summary: filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

